const express = require('express');
const jwt = require('jsonwebtoken');
const axios = require('axios');

const app = express();

app.use(express.json());

// OIDC client configuration
const clientId = 'your_client_id';
const clientSecret = 'your_client_secret';
const authorizationUrl = 'https://your_authorization_url';
const tokenUrl = 'https://your_token_url';
const userInfoUrl = 'https://your_userinfo_url';

// OIDC endpoints
app.get('/auth', (req, res) => {
  const state = generateState();
  const nonce = generateNonce();
  const redirectUri = `http://localhost:3000/callback`;
  const scope = 'openid email profile';
  const responseType = 'code';
  const prompt = 'consent';

  res.redirect(`${authorizationUrl}?client_id=${clientId}&state=${state}&nonce=${nonce}&redirect_uri=${redirectUri}&scope=${scope}&response_type=${responseType}&prompt=${prompt}`);
});

app.get('/callback', (req, res) => {
  const code = req.query.code;
  const state = req.query.state;
  const nonce = req.query.nonce;

  if (!state || !nonce) {
    return res.status(401).send('Invalid request');
  }

  axios.post(`${tokenUrl}`, `grant_type=authorization_code&code=${code}&redirect_uri=${redirectUri}&client_id=${clientId}&client_secret=${clientSecret}`).then((response) => {
    const accessToken = response.data.access_token;
    const idToken = response.data.id_token;

    if (!accessToken || !idToken) {
      return res.status(401).send('Invalid request');
    }

    jwt.decode(idToken, (err, decoded) => {
      if (err) {
        return res.status(500).send('Error decoding JWT');
      }

      const userInfo = decoded.user_info;
      const sub = userInfo.sub;
      const email = userInfo.email;
      const name = userInfo.name;

      // Create user session based on the decoded claims
      req.session.sub = sub;
      req.session.email = email;
      req.session.name = name;

      res.redirect(`http://localhost:3000/profile`);
    });
  }).catch((error) => {
    console.log(error);
    return res.status(500).send('Error exchanging code for tokens');
  });
});

app.get('/profile', (req, res) => {
  const sub = req.session.sub;
  const email = req.session.email;
  const name = req.session.name;

  if (!sub || !email || !name) {
    return res.status(401).send('Invalid request');
  }

  res.render('profile', { sub, email, name });
});

